def print_board(board):
    for row in board:
        print(" | ".join(row))
        print("-" * 5)

def check_winner(board, player):
    # Check rows, columns, and diagonals for a win
    for row in board:
        if all([spot == player for spot in row]):
            return True
    for col in range(len(board)):
        if all([board[row][col] == player for row in range(len(board))]):
            return True
    if all([board[i][i] == player for i in range(len(board))]):
        return True
    if all([board[i][len(board) - 1 - i] == player for i in range(len(board))]):
        return True
    return False

def is_full(board):
    return all([spot != " " for row in board for spot in row])

def tic_tac_toe():
    board = [[" " for _ in range(3)] for _ in range(3)]
    current_player = "X"

    while True:
        print_board(board)
        row = int(input(f"Player {current_player}, enter a row (0, 1, 2): "))
        col = int(input(f"Player {current_player}, enter a column (0, 1, 2): "))

        if board[row][col] == " ":
            board[row][col] = current_player
            if check_winner(board, current_player):
                print_board(board)
                print(f"Player {current_player} wins!")
                break
            elif is_full(board):
                print_board(board)
                print("It's a draw!")
                break
            else:
                current_player = "O" if current_player == "X" else "X"
        else:
            print("That spot is already taken. Try again.")

if __name__ == "__main__":
    tic_tac_toe()
