```cpp
#include <unistd.h>
#include <stdio.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    int fd[2];  // File descriptor for pipe
    pid_t pid;

    // Create a pipe
    if (pipe(fd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a child process
    pid = fork();
    if (pid == -1) {
        perror("fork");
        return 1;
    }

    // Child process
    if (pid == 0) {
        // Close unused parts of the pipe
        close(fd[1]);  // Close write end in child
        close(fd[0]);  // Close read end in child

        // Redirect stdin and stdout to the pipe's read end
        dup2(fd[0], STDIN_FILENO);
        dup2(fd[0], STDOUT_FILENO);

        // Execute a new program
        execlp("ls", "ls", "-l", NULL);
        perror("execlp");  // If execlp fails
        exit(EXIT_FAILURE);
    }

    // Parent process
    close(fd[0]);  // Close unused parts of the pipe in parent
    close(fd[1]);  // Close write end in parent

    // Do something with the write end if needed
    write(fd[1], "Hello from parent\n", 20);

    // Wait for the child to finish
    wait(NULL);

    return 0;
}
```

In this example, a pipe is created, and a new process is forked. The child process closes unnecessary ends of the pipe and redirects its `stdin` and `stdout` to the read end of the pipe. It then executes the `ls -l` command. The parent process waits for the child to finish. You can modify this code to suit your specific needs.

